class Trie {
private:
    static const int MAX_BITS = 15;
    vector<vector<int>> children;

public:
    Trie() : children(1, vector<int>(2, -1)) {}

    void insert(int num) {
        int node = 0;
        for (int i = MAX_BITS; i >= 0; --i) {
            int bit = (num >> i) & 1;
            if (children[node][bit] == -1) {
                children[node][bit] = children.size();
                children.emplace_back(vector<int>(2, -1));
            }
            node = children[node][bit];
        }
    }

    int query(int num, int x) {
        int count = 0, node = 0;
        for (int i = MAX_BITS; i >= 0; --i) {
            int bit = (num >> i) & 1;
            if (((x >> i) & 1) == 1) {
                if (children[node][bit] != -1) count += countNodes(node, bit, i - 1);
                node = getNode(node, 1 - bit, i - 1);
            } else {
                node = getNode(node, bit, i - 1);
            }
            if (node == -1) break;
        }
        if (node != -1) count += countNodes(node, 0, -1);
        return count;
    }

    int countNodes(int node, int bit, int depth) {
        if (node == -1) return 0;
        if (depth == -1) return 1;
        int count = 0;
        if (children[node][bit] != -1) count += countNodes(children[node][bit], bit, depth - 1);
        if (children[node][1 - bit] != -1) count += countNodes(children[node][1 - bit], bit, depth - 1);
        return count;
    }

    int getNode(int node, int bit, int depth) {
        if (node == -1 || children[node][bit] == -1) return -1;
        if (depth == -1) return node;
        return getNode(children[node][bit], bit, depth);
    }
};
